#include <bits/stdc++.h>
using namespace std;
long long n,m,a,v,s[500005],sb;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m>>a>>v;
	a+=v;
	v=0;
	for(long long i=0; i<n; i++) {
		long long x,y;
		cin>>x>>y;
		if(x<=a) {
			s[++v]=y;
		}
	}
	sort(s+1,s+1+v);
	for(long long i=1; i<=v; i++) {
		sb+=s[i];
		if(sb>m) {
			cout<<i-1;
			return 0;
		}
	}
	cout<<0;
	return 0;
}
